{
  "name": "Ponkhiiraj Travel Calculator",
  "description": "A specialized tour expense calculator for Ponkhiiraj Travel with complex bus fare distribution and offline storage capability.",
  "requestFramePermissions": []
}

export interface OtherExpense {
  id: string;
  name: string;
  totalAmount: number;
  guestCount: number;
}

export interface TourData {
  id: string;
  tourName: string;
  date: string;
  busCost: number;
  tollTipCost: number;
  totalGuests: number;
  discount1Guests: number;
  discount1Amount: number;
  discount2Guests: number;
  discount2Amount: number;
  otherExpenses: OtherExpense[];
}

export interface CalculationResult {
  totalBusCost: number;
  regularBusFare: number;
  discount1BusFare: number;
  discount2BusFare: number;
  otherPerPersonTotal: number;
  totalPerRegular: number;
  totalPerDiscount1: number;
  totalPerDiscount2: number;
}

import { TourData, CalculationResult } from '../types';

export const calculateTourCosts = (data: TourData): CalculationResult => {
  const totalBusCost = (data.busCost || 0) + (data.tollTipCost || 0);
  const totalGuests = data.totalGuests || 1;

  // Formula: Gap = (Discount 1 Guest Count * Discount Amount) + (Discount 2 Guest Count * Discount Amount)
  const gap = (data.discount1Guests * data.discount1Amount) + (data.discount2Guests * data.discount2Amount);

  // Regular Bus Fare = (Total Bus Cost + Discount Gap) / Total Received Guests
  const regularBusFare = (totalBusCost + gap) / totalGuests;

  const discount1BusFare = regularBusFare - data.discount1Amount;
  const discount2BusFare = regularBusFare - data.discount2Amount;

  // Calculate sum of other expenses per person
  const otherPerPersonTotal = data.otherExpenses.reduce((acc, item) => {
    const perPerson = item.guestCount > 0 ? item.totalAmount / item.guestCount : 0;
    return acc + perPerson;
  }, 0);

  return {
    totalBusCost,
    regularBusFare,
    discount1BusFare,
    discount2BusFare,
    otherPerPersonTotal,
    totalPerRegular: regularBusFare + otherPerPersonTotal,
    totalPerDiscount1: discount1BusFare + otherPerPersonTotal,
    totalPerDiscount2: discount2BusFare + otherPerPersonTotal,
  };
};

export const formatCurrency = (amount: number) => {
  return amount.toLocaleString('bn-BD', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
};

export const generateSummaryText = (data: TourData, results: CalculationResult): string => {
  const otherExpensesText = data.otherExpenses
    .map(ex => `${ex.name} ${ex.totalAmount}÷${ex.guestCount}= ${Math.round(ex.totalAmount / ex.guestCount)}`)
    .join('\n');

  return `${data.tourName}

বাস ${data.busCost}
টোল,বকশিস, বিরতি ${data.tollTipCost}
মোট ${results.totalBusCost}

গেস্ট: ${data.totalGuests} জন

বেসিক ভাড়া ${results.totalBusCost}/${data.totalGuests}=${(results.totalBusCost/data.totalGuests).toFixed(2)}

রেগুলার সিট: ${Math.round(results.regularBusFare)}
${data.discount1Amount > 0 ? `ডিসকাউন্ট ১ (ছাড় ${data.discount1Amount}): ${Math.round(results.discount1BusFare)}\n` : ''}${data.discount2Amount > 0 ? `ডিসকাউন্ট ২ (ছাড় ${data.discount2Amount}): ${Math.round(results.discount2BusFare)}\n` : ''}
${otherExpensesText}

মুল সিট জনপ্রতি ${Math.round(results.totalPerRegular)}
${data.discount1Amount > 0 ? `ডিসকাউন্ট ১ জনপ্রতি ${Math.round(results.totalPerDiscount1)}\n` : ''}${data.discount2Amount > 0 ? `ডিসকাউন্ট ২ জনপ্রতি ${Math.round(results.totalPerDiscount2)}` : ''}`;
};

