  const results = calculateTourCosts(currentTour);

  const handleCopy = () => {
    const text = generateSummaryText(currentTour, results);
    navigator.clipboard.writeText(text);
    setShowCopyToast(true);
    setTimeout(() => setShowCopyToast(false), 2000);
