        >
          <PlusIcon className="w-6 h-6" /> নতুন হিসাব
        </button>
      </nav>

      {/* Copy Notification Toast */}
      {showCopyToast && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-green-500 text-white px-6 py-2 rounded-full shadow-lg z-[100] animate-bounce">
          কপি করা হয়েছে!
        </div>
      )}
    </div>
  );
};

