import React, { useState, useEffect } from 'react';
import { TourData, OtherExpense } from './types';
import { calculateTourCosts, generateSummaryText } from './utils/calculations';
import { 
  PlusIcon, 
  TrashIcon, 
  ClipboardDocumentIcon, 
  DevicePhoneMobileIcon,
  ArchiveBoxIcon,
  CalculatorIcon,
  CheckCircleIcon,
  ArrowPathIcon,
  UserGroupIcon,
  TruckIcon,
  MapPinIcon,
  SparklesIcon
} from '@heroicons/react/24/outline';

const INITIAL_STATE: TourData = {
  id: '',
  tourName: '',
  date: new Date().toISOString().split('T')[0],
  busCost: 0,
  tollTipCost: 0,
  totalGuests: 0,
  discount1Guests: 0,
  discount1Amount: 0,
  discount2Guests: 0,
  discount2Amount: 0,
  otherExpenses: [
    { id: '1', name: 'খাবার', totalAmount: 0, guestCount: 0 },
    { id: '2', name: 'হোস্ট ফি', totalAmount: 0, guestCount: 0 }
  ]
};

const App: React.FC = () => {
  const [currentTour, setCurrentTour] = useState<TourData>({ ...INITIAL_STATE, id: Date.now().toString() });
  const [history, setHistory] = useState<TourData[]>([]);
  const [view, setView] = useState<'calc' | 'history'>('calc');
  const [showCopyToast, setShowCopyToast] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('ponkhiiraj_tours');
    if (saved) {
      setHistory(JSON.parse(saved));
    }
  }, []);

  const saveToHistory = () => {
    if (!currentTour.tourName) {
      alert('অনুগ্রহ করে ট্যুরের নাম লিখুন');
      return;
    }
    const updatedHistory = [{...currentTour, id: Date.now().toString()}, ...history.filter(h => h.id !== currentTour.id)].slice(0, 30);
    setHistory(updatedHistory);
    localStorage.setItem('ponkhiiraj_tours', JSON.stringify(updatedHistory));
    alert('হিসাবটি সফলভাবে সেভ করা হয়েছে!');
  };

  const deleteFromHistory = (id: string) => {
    const updatedHistory = history.filter(h => h.id !== id);
    setHistory(updatedHistory);
    localStorage.setItem('ponkhiiraj_tours', JSON.stringify(updatedHistory));
  };

  const results = calculateTourCosts(currentTour);

  const handleCopy = () => {
    const text = generateSummaryText(currentTour, results);
    navigator.clipboard.writeText(text);
    setShowCopyToast(true);
    setTimeout(() => setShowCopyToast(false), 2000);
  };

  const updateOtherExpense = (id: string, field: keyof OtherExpense, value: string | number) => {
    setCurrentTour(prev => ({
      ...prev,
      otherExpenses: prev.otherExpenses.map(ex => 
        ex.id === id ? { ...ex, [field]: value } : ex
      )
    }));
  };

  const addOtherExpense = () => {
    const newEx: OtherExpense = {
      id: Date.now().toString(),
      name: '',
      totalAmount: 0,
      guestCount: currentTour.totalGuests
    };
    setCurrentTour(prev => ({
      ...prev,
      otherExpenses: [...prev.otherExpenses, newEx]
    }));
  };

  const removeOtherExpense = (id: string) => {
    setCurrentTour(prev => ({
      ...prev,
      otherExpenses: prev.otherExpenses.filter(ex => ex.id !== id)
    }));
  };

  const resetCalculator = () => {
    if (window.confirm('আপনি কি সব ইনপুট ক্লিয়ার করতে চান?')) {
      setCurrentTour({ ...INITIAL_STATE, id: Date.now().toString() });
    }
