  PlusIcon, 
  TrashIcon, 
  ClipboardDocumentIcon, 
  ArchiveBoxIcon,
  CalculatorIcon,
  CheckCircleIcon,
  ArrowPathIcon,
  UserGroupIcon,
  TruckIcon,
  MapPinIcon,
  SparklesIcon
} from '@heroicons/react/24/outline';

/** --- TYPES --- **/
interface OtherExpense {
  id: string;
  name: string;
  totalAmount: number;
  guestCount: number;
}

interface TourData {
  id: string;
  tourName: string;
  date: string;
  busCost: number;
  tollTipCost: number;
  totalGuests: number;
  discount1Guests: number;
  discount1Amount: number;
  discount2Guests: number;
  discount2Amount: number;
  otherExpenses: OtherExpense[];
}

interface CalculationResult {
  totalBusCost: number;
  regularBusFare: number;
  discount1BusFare: number;
  discount2BusFare: number;
  otherPerPersonTotal: number;
  totalPerRegular: number;
  totalPerDiscount1: number;
  totalPerDiscount2: number;
}

/** --- UTILS --- **/
const calculateTourCosts = (data: TourData): CalculationResult => {
  const totalBusCost = (data.busCost || 0) + (data.tollTipCost || 0);
  const totalGuests = data.totalGuests || 0;

  if (totalGuests === 0) {
    return {
      totalBusCost, regularBusFare: 0, discount1BusFare: 0, discount2BusFare: 0,
      otherPerPersonTotal: 0, totalPerRegular: 0, totalPerDiscount1: 0, totalPerDiscount2: 0,
    };
  }

  // Formula per User Request:
  // Basic Fare = Total Bus / Total Guests
  const basicFare = totalBusCost / totalGuests;

  // Gap = (D1G * D1A) + (D2G * D2A)
  const gap = (data.discount1Guests * data.discount1Amount) + (data.discount2Guests * data.discount2Amount);

  // Regular Guests = Total - (D1G + D2G)
  const regularSeatGuests = totalGuests - (data.discount1Guests + data.discount2Guests);

  // Regular Fee = Basic Fare + (Gap / Regular Seat Guests)
  const regularBusFare = regularSeatGuests > 0 
    ? Math.ceil(basicFare + (gap / regularSeatGuests)) 
    : Math.ceil(basicFare);

  // Discount Seat = Basic Fare - Discount Price
  const discount1BusFare = Math.ceil(basicFare - data.discount1Amount);
  const discount2BusFare = Math.ceil(basicFare - data.discount2Amount);

  // Logistics calculations (Math.ceil as requested)
  const otherPerPersonTotal = data.otherExpenses.reduce((acc, item) => {
    const perPerson = item.guestCount > 0 ? Math.ceil(item.totalAmount / item.guestCount) : 0;
    return acc + perPerson;
  }, 0);

  return {
    totalBusCost,
    regularBusFare,
    discount1BusFare,
    discount2BusFare,
    otherPerPersonTotal,
    totalPerRegular: regularBusFare + otherPerPersonTotal,
    totalPerDiscount1: discount1BusFare + otherPerPersonTotal,
    totalPerDiscount2: discount2BusFare + otherPerPersonTotal,
  };
};

const generateSummaryText = (data: TourData, results: CalculationResult): string => {
  const basicPP = data.totalGuests > 0 ? Math.ceil(results.totalBusCost / data.totalGuests) : 0;
  const otherExpensesText = data.otherExpenses
    .map(ex => {
      const perPerson = ex.guestCount > 0 ? Math.ceil(ex.totalAmount / ex.guestCount) : 0;
      return `${ex.name} ${ex.totalAmount}÷${ex.guestCount}= ${perPerson}`;
    })
    .join('\n');

  return `${data.tourName || 'পঙ্খিরাজ ট্রাভেল'}\n
বাস ${data.busCost}
টোল,বকশিস, বিরতি ${data.tollTipCost}
মোট ${results.totalBusCost}

গেস্ট: ${data.totalGuests} জন

বেসিক ভাড়া ${results.totalBusCost}/${data.totalGuests}=${basicPP}

রেগুলার সিট: ${results.regularBusFare}
${data.discount1Guests > 0 ? `ডিসকাউন্ট ১: ${results.discount1BusFare}\n` : ''}${data.discount2Guests > 0 ? `ডিসকাউন্ট ২: ${results.discount2BusFare}\n` : ''}
${otherExpensesText}

মুল সিট জনপ্রতি ${results.totalPerRegular}
${data.discount1Guests > 0 ? `ডিসকাউন্ট ১ জনপ্রতি ${results.totalPerDiscount1}\n` : ''}${data.discount2Guests > 0 ? `ডিসকাউন্ট ২ জনপ্রতি ${results.totalPerDiscount2}` : ''}`;
};

