            <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
              <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-4 block">বাস ও ট্রান্সপোর্ট</span>
              <div className="grid grid-cols-2 gap-4 mb-4">
                <div><label className={labelCls}>বাস ভাড়া</label><input type="number" value={data.busCost || ''} onChange={e => setData({...data, busCost: parseInt(e.target.value) || 0})} className={inputCls} /></div>
                <div><label className={labelCls}>টোল ও অন্যান্য</label><input type="number" value={data.tollTipCost || ''} onChange={e => setData({...data, tollTipCost: parseInt(e.target.value) || 0})} className={inputCls} /></div>
              </div>

              <div className="space-y-3">
                <div className="bg-orange-50 p-3 rounded-xl border border-orange-200 grid grid-cols-2 gap-3">
                  <div className="col-span-2 text-[9px] font-black text-orange-600 uppercase">ডিসকাউন্ট স্লট ১</div>
                  <input type="number" placeholder="গেস্ট সংখ্যা" value={data.discount1Guests || ''} onChange={e => setData({...data, discount1Guests: parseInt(e.target.value) || 0})} className={`${inputCls} !py-2 border-orange-300`} />
                  <input type="number" placeholder="ছাড় (৳)" value={data.discount1Amount || ''} onChange={e => setData({...data, discount1Amount: parseInt(e.target.value) || 0})} className={`${inputCls} !py-2 border-orange-300`} />
                </div>
                <div className="bg-blue-50 p-3 rounded-xl border border-blue-200 grid grid-cols-2 gap-3">
                  <div className="col-span-2 text-[9px] font-black text-blue-600 uppercase">ডিসকাউন্ট স্লট ২</div>
                  <input type="number" placeholder="গেস্ট সংখ্যা" value={data.discount2Guests || ''} onChange={e => setData({...data, discount2Guests: parseInt(e.target.value) || 0})} className={`${inputCls} !py-2 border-blue-300`} />
                  <input type="number" placeholder="ছাড় (৳)" value={data.discount2Amount || ''} onChange={e => setData({...data, discount2Amount: parseInt(e.target.value) || 0})} className={`${inputCls} !py-2 border-blue-300`} />
                </div>
              </div>
            </div>

            {/* Other Expenses */}
            <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm space-y-4">
              <div className="flex justify-between items-center">
                <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">অন্যান্য লজিস্টিকস</span>
                <button onClick={() => setData({...data, otherExpenses: [...data.otherExpenses, { id: Date.now().toString(), name: '', totalAmount: 0, guestCount: data.totalGuests }]})} className="bg-slate-900 text-white px-3 py-1 rounded-lg text-[10px] font-bold uppercase hover:bg-black transition">+ যোগ করুন</button>
              </div>
              <div className="space-y-3">
                {data.otherExpenses.map((ex, idx) => (
                  <div key={ex.id} className="grid grid-cols-12 gap-2 items-center bg-slate-50 p-2 rounded-xl border border-slate-100">
                    <div className="col-span-5"><input type="text" placeholder="নাম" value={ex.name} onChange={e => { const items = [...data.otherExpenses]; items[idx].name = e.target.value; setData({...data, otherExpenses: items}) }} className={`${inputCls} !py-1.5 !px-2 !text-[12px] border-slate-200`} /></div>
                    <div className="col-span-3"><input type="number" placeholder="টাকা" value={ex.totalAmount || ''} onChange={e => { const items = [...data.otherExpenses]; items[idx].totalAmount = parseInt(e.target.value) || 0; setData({...data, otherExpenses: items}) }} className={`${inputCls} !py-1.5 !px-2 !text-[12px] border-slate-200`} /></div>
                    <div className="col-span-3"><input type="number" placeholder="প্যাক্স" value={ex.guestCount || ''} onChange={e => { const items = [...data.otherExpenses]; items[idx].guestCount = parseInt(e.target.value) || 0; setData({...data, otherExpenses: items}) }} className={`${inputCls} !py-1.5 !px-2 !text-[12px] border-slate-200`} /></div>
                    <div className="col-span-1 flex justify-center"><button onClick={() => setData({...data, otherExpenses: data.otherExpenses.filter(i => i.id !== ex.id)})} className="text-slate-400 hover:text-rose-500 transition"><TrashIcon className="w-4 h-4" /></button></div>
                  </div>
                ))}
              </div>
            </div>
          </>
        ) : (
          <div className="space-y-3">
            {history.length === 0 ? (
              <div className="text-center py-20 text-slate-300">
                <ArchiveBoxIcon className="w-16 h-16 mx-auto opacity-20" />
                <p className="font-bold mt-2">কোনো হিস্ট্রি নেই</p>
              </div>
            ) : (
              history.map(item => (
                <div key={item.id} onClick={() => { setData(item); setView('calc'); }} className="bg-white p-4 rounded-2xl border border-slate-200 flex justify-between items-center shadow-sm active:scale-95 transition-transform cursor-pointer">
                  <div className="flex items-center gap-3">
                    <div className="bg-slate-100 p-2 rounded-lg">
                      <UserGroupIcon className="w-5 h-5 text-slate-600" />
                    </div>
                    <div>
                      <h4 className="text-sm font-bold text-slate-900 truncate w-40">{item.tourName || 'Untitled Tour'}</h4>
                      <p className="text-[10px] text-slate-500 font-bold">{item.date} • {item.totalGuests} Guests</p>
                    </div>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); setHistory(history.filter(h => h.id !== item.id)) }} className="text-slate-300 hover:text-rose-500 p-2"><TrashIcon className="w-5 h-5" /></button>
                </div>
              ))
            )}
          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 right-0 p-4 max-w-md mx-auto pointer-events-none">
        <div className="bg-slate-900 text-white p-5 rounded-[2.5rem] flex justify-between items-center shadow-2xl border border-white/10 pointer-events-auto">
          <div className="flex gap-6 pl-4">
            <div>
              <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest">রেগুলার</p>
              <p className="text-2xl font-black">{results.totalReg}৳</p>
            </div>
            {(data.discount1Guests > 0 || data.discount2Guests > 0) && (
              <div className="border-l border-white/10 pl-6">
                <p className="text-[8px] font-black text-orange-400 uppercase tracking-widest">ডিসকাউন্ট</p>
                <p className="text-2xl font-black text-orange-100">{results.totalD1}৳</p>
              </div>
            )}
          </div>
          <div className="flex gap-2">
            <button onClick={saveTour} title="Save" className="w-12 h-12 bg-white/5 hover:bg-white/10 rounded-2xl flex items-center justify-center border border-white/10 transition active:scale-90">
              <CheckCircleIcon className="w-6 h-6" />
            </button>
            <button onClick={copyText} className="bg-indigo-600 hover:bg-indigo-500 px-6 h-12 rounded-2xl font-black text-xs flex items-center gap-2 shadow-lg active:scale-95 transition-all">
              <ClipboardDocumentIcon className="w-5 h-5" /> Copy
            </button>
          </div>
        </div>
      </footer>

      {copied && (
        <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-slate-900/95 text-white px-8 py-3 rounded-full text-xs font-black shadow-2xl animate-bounce z-[100] border border-white/20">
          সফলভাবে কপি হয়েছে!
        </div>
      )}
    </div>
  );
};

const rootElement = document.getElementById('root');
if (rootElement) {
  createRoot(rootElement).render(<App />);
}

